import React, { useState, useEffect } from "react";
import { useParams, useLocation, useNavigate } from "react-router-dom";
import axios from "axios";
import products from "../data/ProductData";
import "../index.css";

const Checkout = () => {
  const { id } = useParams();
  const location = useLocation();
  const navigate = useNavigate();

  const [product, setProduct] = useState(location.state?.product || null);
  const [promoCode, setPromoCode] = useState("");
  const [discount, setDiscount] = useState(0);
  const [address, setAddress] = useState("");
  const [orderPlaced, setOrderPlaced] = useState(false);

  useEffect(() => {
    if (product) return; // Already have product from navigation state

    // Try dummy data first
    const dummy = products.find((p) => String(p.id) === id);
    if (dummy) {
      setProduct(dummy);
      return;
    }

    // Try backend product if not found in dummy data
    axios
      .get('http://localhost:5000/api/products/${id}')
      .then((res) => setProduct(res.data))
      .catch(() => setProduct({ name: "Unknown Product", price: 0, _id: id }));
  }, [id, product]);

  const handleApplyPromo = () => {
    if (promoCode.trim().toLowerCase() === "save10") {
      setDiscount(0.1); // 10% discount
      alert("Promo code applied! 10% discount added.");
    } else {
      setDiscount(0);
      alert("Invalid promo code");
    }
  };

  const handlePlaceOrder = () => {
    if (!address.trim()) {
      alert("Please enter your address before placing the order.");
      return;
    }

    setOrderPlaced(true);

    // Send order to backend later if needed
    console.log("Order placed:", { product, address, promoCode });

    setTimeout(() => navigate("/orders"), 2000);
  };

  if (!product) return <p>Loading...</p>;
  if (orderPlaced)
    return <h2 className="success-msg">✅ Order placed successfully!</h2>;

  const tax = Math.round(product.price * 0.02);
  const discountAmount = Math.round(product.price * discount);
  const discountedPrice = Math.round(product.price - discountAmount);
  const total = discountedPrice + tax;

  return (
    <div className="checkout-summary-container">
      <h2 className="summary-title">Checkout</h2>
      <div className="divider"></div>

      {/* Product Info */}
      <div className="summary-section">
        <h4>PRODUCT</h4>
        <p>{product.name}</p>
        <p>Price: ₹{product.price}</p>
      </div>

      {/* Address Section */}
      <div className="summary-section">
        <h4>ENTER DELIVERY ADDRESS</h4>
        <textarea
          placeholder="Enter your full delivery address"
          value={address}
          onChange={(e) => setAddress(e.target.value)}
          className="address-box"
          required
        ></textarea>
      </div>

      {/* Promo Code */}
      <div className="summary-section">
        <h4>PROMO CODE</h4>
        <div className="promo-row">
          <input
            type="text"
            placeholder="Enter promo code"
            value={promoCode}
            onChange={(e) => setPromoCode(e.target.value)}
          />
          <button className="apply-btn" onClick={handleApplyPromo}>
            Apply
          </button>
        </div>
      </div>

      <div className="divider"></div>

      {/* Price Summary */}
      <div className="summary-totals">
        <div className="row">
          <span>Price</span>
          <span>₹{product.price}</span>
        </div>
        <div className="row">
          <span>Shipping Fee</span>
          <span>Free</span>
        </div>
        <div className="row">
          <span>Tax (2%)</span>
          <span>₹{tax}</span>
        </div>
        {discount > 0 && (
          <div className="row discount">
            <span>Discount ({discount * 100}%)</span>
            <span>-₹{discountAmount}</span>
          </div>
        )}
        <div className="divider"></div>
        <div className="row total">
          <strong>Total</strong>
          <strong>₹{total}</strong>
        </div>
      </div>

      <button className="place-order-btn" onClick={handlePlaceOrder}>
        Place Order
      </button>
    </div>
  );
};

export default Checkout;
